SELECT COUNT(*) AS total_contacts
FROM contacts
WHERE certified = 1 AND first_class_mail = 0;

SELECT COUNT(contact_id) 
FROM contacts 
WHERE certified = 1 AND preferred_communication = 'Email';

SELECT COUNT(*) AS certified_email_contacts
FROM contacts
WHERE certified = 1 AND preferred_communication = 'Email';

SELECT certified, COUNT(*) AS contact_count
FROM contacts
GROUP BY certified;

SELECT COUNT(*) AS total_correspondence
FROM correspondence_history
WHERE contact_id = 1;
